const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const express = require('express');
const bodyParser = require('body-parser');

class GrpcClient {
  constructor(protoPath, packageName, serviceName, serverAddress) {
    const packageDefinition = protoLoader.loadSync(protoPath, {
      keepCase: true,
      longs: String,
      enums: String,
      defaults: true,
      oneofs: true
    });

    const protoDescriptor = grpc.loadPackageDefinition(packageDefinition);
    const servicePackage = packageName.split('.').reduce((obj, key) => obj[key], protoDescriptor);
    
    this.client = new servicePackage[serviceName](
      serverAddress,
      grpc.credentials.createInsecure()
    );
  }

  call(method, request, httpHeaders) {
    return new Promise((resolve, reject) => {
      const metadata = this.createMetadataFromHttpHeaders(httpHeaders);
      
      this.client[method](request, metadata, (error, response) => {
        if (error) {
          reject(error);
        } else {
          resolve(response);
        }
      });
    });
  }

  createMetadataFromHttpHeaders(httpHeaders) {
    const metadata = new grpc.Metadata();
    
    const headersToForward = [
      'user-agent',
      'x-forwarded-for',
      'x-forwarded-proto',
      'x-forwarded-host',
      'x-real-ip',
      'authorization',
      'content-type',
      'accept',
      'accept-language',
      'accept-encoding',
      'referer',
      'origin',
      'x-request-id',
      'x-correlation-id',
      'x-trace-id',
      'x-session-id',
      'x-api-key',
      'x-client-id',
      'x-tenant-id'
    ];

    for (const [key, value] of Object.entries(httpHeaders)) {
      const lowerKey = key.toLowerCase();
      
      if (headersToForward.includes(lowerKey) || lowerKey.startsWith('x-')) {
        if (Array.isArray(value)) {
          value.forEach(v => metadata.add(lowerKey, v));
        } else if (value) {
          metadata.add(lowerKey, value);
        }
      }
    }

    return metadata;
  }

  callWithStreaming(method, request, httpHeaders) {
    const metadata = this.createMetadataFromHttpHeaders(httpHeaders);
    return this.client[method](request, metadata);
  }
}

class HttpToGrpcGateway {
  constructor() {
    this.app = express();
    this.grpcClients = new Map();
    
    this.app.use(bodyParser.json());
    this.app.use(bodyParser.urlencoded({ extended: true }));
  }

  registerService(route, protoPath, packageName, serviceName, serverAddress) {
    const client = new GrpcClient(protoPath, packageName, serviceName, serverAddress);
    this.grpcClients.set(route, client);
  }

  setupRoutes() {
    this.app.all('/:service/:method', async (req, res) => {
      try {
        const { service, method } = req.params;
        const client = this.grpcClients.get(service);

        if (!client) {
          return res.status(404).json({ error: 'Service not found' });
        }

        const request = req.method === 'GET' ? req.query : req.body;
        const headers = req.headers;

        const response = await client.call(method, request, headers);
        res.json(response);
      } catch (error) {
        res.status(500).json({
          error: error.message,
          code: error.code,
          details: error.details
        });
      }
    });

    this.app.post('/:service/:method/stream', (req, res) => {
      try {
        const { service, method } = req.params;
        const client = this.grpcClients.get(service);

        if (!client) {
          return res.status(404).json({ error: 'Service not found' });
        }

        const request = req.body;
        const headers = req.headers;
        const call = client.callWithStreaming(method, request, headers);

        res.setHeader('Content-Type', 'application/json');
        res.setHeader('Transfer-Encoding', 'chunked');

        call.on('data', (data) => {
          res.write(JSON.stringify(data) + '\n');
        });

        call.on('end', () => {
          res.end();
        });

        call.on('error', (error) => {
          res.status(500).json({
            error: error.message,
            code: error.code,
            details: error.details
          });
        });
      } catch (error) {
        res.status(500).json({ error: error.message });
      }
    });
  }

  start(port) {
    this.setupRoutes();
    this.app.listen(port, () => {
      console.log(`HTTP to gRPC Gateway listening on port ${port}`);
    });
  }
}

const gateway = new HttpToGrpcGateway();

gateway.registerService(
  'users',
  './proto/users.proto',
  'users',
  'UserService',
  'localhost:50051'
);

gateway.registerService(
  'products',
  './proto/products.proto',
  'products',
  'ProductService',
  'localhost:50052'
);

gateway.start(3000);

